```cpp
#pragma once

#include <reaction/reaction.h>
#include <tuple>

namespace test_reaction {

// ============================================
// Function implementations
// ============================================

/**
 * Function: Test batch execution reduces recomputation count
 *
 * @param initialA Initial value for variable a
 * @param initialB Initial value for variable b
 * @param nonBatchA Value to set a without batching
 * @param nonBatchB Value to set b without batching
 * @param batchA Value to set a within batch
 * @param batchB Value to set b within batch
 * @return std::tuple<int, int, int> {final sum, count after non-batch updates, count after batch updates}
 */
std::tuple<int, int, int> test_batch_execution(int initialA,
                                               int initialB,
                                               int nonBatchA,
                                               int nonBatchB,
                                               int batchA,
                                               int batchB) {
    // 1. Create reactive variables
    auto a = reaction::value(initialA);
    auto b = reaction::value(initialB);

    // 2. Create variable to track recomputation count
    int recompute_count = 0;

    // 3. Create calculation
    // The lambda captures the variables and the counter by reference
    auto sum = reaction::react([&] {
        recompute_count++;
        return a.get() + b.get();
    });

    // We attach an observer to ensure the calculation is triggered on updates.
    // Without an observer, lazy evaluation might defer computation until access.
    auto obs = reaction::observe(sum, [](int) {});

    // 4. Perform non-batch updates
    // Each update triggers a recomputation immediately (due to the observer)
    a.value(nonBatchA);
    b.value(nonBatchB);

    // 5. Record recompute count after non-batch updates
    int count_non_batch = recompute_count;

    // 6. Create batch context & 7. Execute batch
    // Updates inside the batch block are deferred until the end of the block
    reaction::batch([&] {
        a.value(batchA);
        b.value(batchB);
    });

    // 8. Record recompute count after batch updates
    // The calculation should have run only once for the batch of updates
    int count_batch = recompute_count;

    // 9. Return final sum and counts
    return {sum(), count_non_batch, count_batch};
}

}  // namespace test_reaction
