#include "test_observer_state_rollback.h"

#include <reaction/reaction.h>

namespace test_reaction {

void RecordingNode::valueChanged(bool changed) {
    if (changed) {
        m_notifications++;
    }
    // Propagate notification to downstream observers
    reaction::ObserverNode::valueChanged(changed);
}

int RecordingNode::notificationCount() const {
    return m_notifications;
}

RollbackObservation test_observer_state_rollback() {
    // 1. Create RecordingNode instances
    auto sensor1 = std::make_shared<RecordingNode>();
    auto sensor2 = std::make_shared<RecordingNode>();
    auto observer = std::make_shared<RecordingNode>();

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Register nodes
    graph.registerNode(sensor1);
    graph.registerNode(sensor2);
    graph.registerNode(observer);

    // 4. Set up initial dependency (observer depends on sensor1)
    sensor1->addOneObserver(observer);

    // 5. Save node state for rollback
    graph.saveNodeState(observer);

    // 6. Replace dependencies transactionally (observer now depends on sensor2)
    observer->updateObservers(sensor2);

    // 7. Trigger notification on second sensor
    sensor2->valueChanged();

    // 8. Record notification count after second binding
    int notificationsAfterSecondBinding = observer->notificationCount();

    // 9. Execute rollback (should revert observer to depend on sensor1)
    graph.restoreNodeState(observer);

    // 10. Trigger notification on first sensor
    sensor1->valueChanged();

    // 11. Record notification count after rollback
    int notificationsAfterRollback = observer->notificationCount();

    // 12. Return notification counts
    return {notificationsAfterSecondBinding, notificationsAfterRollback};
}

}  // namespace test_reaction
