To implement the `test_observer_collection` function and the `NamedObserverNode` class, we need to create a source file (e.g., `test_observer_collection.cpp`) that includes the provided header.

Since the provided header definition of `NamedObserverNode` does not contain a member variable to store the name, and we cannot modify the header, we will use a static `std::unordered_map` to associate `NamedObserverNode` instances with their names.

Here is the complete content of the implementation file:

```cpp
#include "test_observer_collection.h"

#include <reaction/graph/observer_graph.h>
#include <reaction/core/observer_node.h>
#include <unordered_set>
#include <unordered_map>
#include <mutex>
#include <memory>

namespace test_reaction {

// Static storage for names since the header class definition is fixed
// and does not contain a member for the name.
static std::mutex g_names_mutex;
static std::unordered_map<const NamedObserverNode*, std::string> g_node_names;

NamedObserverNode::NamedObserverNode(std::string name) 
    : reaction::ObserverNode()
{
    std::lock_guard<std::mutex> lock(g_names_mutex);
    g_node_names[this] = std::move(name);
}

const std::string& NamedObserverNode::name() const {
    std::lock_guard<std::mutex> lock(g_names_mutex);
    // Return empty string if not found (should not happen for valid instances)
    static const std::string empty;
    auto it = g_node_names.find(this);
    if (it != g_node_names.end()) {
        return it->second;
    }
    return empty;
}

ObserverCollectionSummary test_observer_collection() {
    // 1. Create NamedObserverNode instances
    auto root = std::make_shared<NamedObserverNode>("root");
    auto direct = std::make_shared<NamedObserverNode>("direct");
    auto transitive = std::make_shared<NamedObserverNode>("transitive");

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Register nodes
    // (Registration is typically handled implicitly by addObserver or node creation,
    // but we ensure they are managed by shared_ptrs here)

    // 4. Set up direct observer relationship: root -> direct
    root->addOneObserver(direct);

    // 5. Set up transitive observer relationship: direct -> transitive
    direct->addOneObserver(transitive);

    // 6. Create NodeSet to store collected observers
    // Using std::unordered_set of shared_ptr to ObserverNode
    using NodeSet = std::unordered_set<std::shared_ptr<reaction::ObserverNode>>;
    NodeSet collected_observers;

    // 7. Collect observers
    // We assume the graph provides a method to collect observers recursively
    graph.collectObservers(root, collected_observers);

    // 8. Check if direct observer is in collected set
    bool containsDirect = collected_observers.find(direct) != collected_observers.end();

    // 9. Check if transitive observer is in collected set
    bool containsTransitive = collected_observers.find(transitive) != collected_observers.end();

    // 10. Return collection summary
    return ObserverCollectionSummary{
        collected_observers.size(),
        containsDirect,
        containsTransitive
    };
}

}  // namespace test_reaction
