CacheStatsSnapshot test_observer_cache_stats() {
    // 1. Create CacheProbeNode instances
    auto node1 = std::make_shared<CacheProbeNode>();
    auto node2 = std::make_shared<CacheProbeNode>();
    auto node3 = std::make_shared<CacheProbeNode>();

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Register nodes
    // In the reaction library, nodes are typically registered implicitly when 
    // observers are added or when they are involved in graph operations.
    // We ensure they are kept alive via shared_ptrs.

    // 4. Set up direct observer relationship
    // node1 -> node2
    graph.addObserver(node1, node2);

    // 5. Set up transitive observer relationship
    // node2 -> node3
    graph.addObserver(node2, node3);

    // 6. Create NodeSet to store collected observers
    reaction::NodeSet collected_observers;

    // 7. Populate cache data
    // This operation traverses the graph and populates the internal cache
    graph.collectObservers(node1, collected_observers);

    // 8. Get cache statistics before cleanup
    auto stats_before = graph.getCacheStats();

    // 9. Trigger cache cleanup
    graph.triggerCacheCleanup();

    // 10. Get cache statistics after cleanup
    auto stats_after = graph.getCacheStats();

    // 11. Close all nodes
    // Release shared pointers to destroy the nodes
    node1.reset();
    node2.reset();
    node3.reset();

    // 12. Return cache stats snapshot
    CacheStatsSnapshot snapshot;
    snapshot.graphEntriesBeforeCleanup = stats_before.entries;
    snapshot.graphEntriesAfterCleanup = stats_after.entries;
    snapshot.graphHitRatioAfterCleanup = stats_after.hitRatio;

    return snapshot;
}

