    // Force evaluation to avoid unused variable warnings
    (void)doubled.get();

    return AlwaysTriggerResult{
        .recomputeCountAfterInit = countAfterInit,
        .recomputeCountAfterDuplicateWrite = countAfterDuplicate,
    };
}

