#include "test_always_trigger.h"
#include <reaction/reaction.h>

namespace test_reaction {

AlwaysTriggerResult test_always_trigger(int initialValue) {
    // 1. Create a reactive variable
    auto var = reaction::MakeVar(initialValue);

    // 2. Create a counter to track recomputation count
    int counter = 0;

    // 3. Create an AlwaysTrig calculation that doubles the value and increments counter
    // The AlwaysTrig policy ensures the calculation notifies observers even if the result is unchanged
    auto calc = reaction::MakeCalc<reaction::AlwaysTrig>([&var, &counter]() {
        counter++;
        return var.Value() * 2;
    });

    // Force evaluation to ensure initialization and first increment of counter
    int val = calc.Value();

    // 4. Store recompute count after initialization
    AlwaysTriggerResult result;
    result.recomputeCountAfterInit = counter;

    // 5. Write the same value again
    var = initialValue;

    // Force evaluation to ensure update propagation
    val = calc.Value();

    // 6. Store recompute count after duplicate write
    result.recomputeCountAfterDuplicateWrite = counter;

    // 7. Force evaluation to avoid unused variable warnings
    (void)val;

    // 8. Return result with recompute counts
    return result;
}

}  // namespace test_reaction
