namespace test_reaction {

struct ResourceSBOState {
    bool smallTypeUsesSBO;
    bool largeTypeUsesSBO;
};

inline ResourceSBOState test_resource_sbo() {
    // 1. Define type aliases for small and large resource types
    // int is typically 4 bytes, fitting within SBO limits.
    using SmallType = int;
    // std::array of 100 doubles is 800 bytes, exceeding typical SBO limits.
    using LargeType = std::array<double, 100>;

    // 2. Create small resource instance
    reaction::Resource<SmallType> small_res(0);

    // 3. Create large resource instance
    reaction::Resource<LargeType> large_res;

    // 4. Query whether small resource uses SBO
    // The Resource class determines SBO usage at compile time via SBOTraits.
    bool small_uses_sbo = reaction::memory::SBOTraits<SmallType>::is_sbo_eligible;

    // 5. Query whether large resource uses SBO
    bool large_uses_sbo = reaction::memory::SBOTraits<LargeType>::is_sbo_eligible;

    // 6. Return resource SBO state
    return {small_uses_sbo, large_uses_sbo};
}

