```cpp
#include "test_last_handle_restore.h"
#include <reaction/reaction.h>
#include <optional>

namespace test_reaction {

LastHandleSnapshot test_last_handle_restore(int initialValue, int updatedValue) {
    LastHandleSnapshot snapshot;

    // 1. Create a reactive variable
    // We use std::optional to manually control the lifetime of the Var handle.
    std::optional<reaction::Var<int>> source = reaction::var(initialValue);

    // 2. Create a calculation with LastHandle policy
    // We specify the LastHandle policy via template argument to calc.
    // The calculation simply mirrors the source value.
    auto calculation = reaction::calc<reaction::Policy::LastHandle>(
        [](int v) { return v; },
        *source
    );

    // 3. Get the initial result
    snapshot.initialValue = calculation.value();

    // 4. Update the source variable
    *source = updatedValue;

    // 5. Get the updated result
    snapshot.afterUpdate = calculation.value();

    // 6. Close the source node
    // Resetting the optional destroys the Var handle. Since the calculation
    // uses LastHandle policy (implying weak observation), the source node
    // is effectively closed/lost to the calculation.
    source.reset();

    // 7. Get the result after source close
    // Due to the LastHandle policy, the calculation should retain the last valid value
    // instead of failing or resetting.
    snapshot.afterSourceClose = calculation.value();

    // 8. Return last handle snapshot
    return snapshot;
}

}  // namespace test_reaction
