#include "test_sbo_storage_info.h"
#include <reaction/memory/sbo_resource.h>

namespace test_reaction {

SboStorageStatus test_sbo_storage_info(int initialSmall,
                                       int updatedSmall,
                                       int largeSeed) {
    // 1. Create a lambda function to make large payload
    auto make_large_payload = [](int seed) {
        LargePayload payload;
        payload.data.fill(seed);
        return payload;
    };

    // 2. Create small SBOResource
    // Using aggregate initialization for SmallPayload
    reaction::memory::SBOResource<SmallPayload> small_resource(SmallPayload{initialSmall});

    // 3. Create large SBOResource
    reaction::memory::SBOResource<LargePayload> large_resource(make_large_payload(largeSeed));

    // 4. Update small resource value
    bool update_reported_change = small_resource.updateValue(SmallPayload{updatedSmall});

    // 5. Get storage information for small resource
    bool small_using_sbo = small_resource.isUsingSBO();
    // The stack usage of the resource is its size (including the internal buffer)
    std::size_t small_stack_usage = sizeof(small_resource);

    // 6. Get storage information for large resource
    bool large_using_sbo = large_resource.isUsingSBO();

    // Verify large resource initialization
    // Since only operator!= is explicitly defaulted/defined, we use !(a != b) to check equality
    bool large_initialized = !(large_resource.getValue() != make_large_payload(largeSeed));

    // 7. Return SBO storage status
    return SboStorageStatus{
        update_reported_change,
        small_using_sbo,
        small_stack_usage,
        large_initialized,
        large_using_sbo
    };
}

}  // namespace test_reaction
