    // Disabling thread safety ensures we start from a known state for the first test
    tm.setThreadSafetyEnabled(false);

    // 3. Create ConditionalMutex instance
    reaction::concurrency::ConditionalMutex mutex;

    ConditionalMutexResult result{};

    {
