        reaction::concurrency::ConditionalLockGuard guard(mutex);

        // 5. Attempt to lock mutex without safety enabled
        // When safety is disabled, the mutex operations are typically no-ops.
        // try_lock() should return true (success) as there is no real lock contention.
        result.tryLockWithoutSafety = mutex.try_lock();

        // If try_lock succeeded, we must unlock to maintain balance, 
        // though for a no-op mutex this might be redundant.
        if (result.tryLockWithoutSafety) {
            mutex.unlock();
        }
    } // 6. Exit guard scope (guard destructor called)

    // 7. Enable thread safety
    tm.setThreadSafetyEnabled(true);

    {
        // 8. Create ConditionalLockGuard in a scope block again
        reaction::concurrency::ConditionalLockGuard guard(mutex);

        // 9. Attempt to lock mutex with safety enabled
        // Now the mutex is active. Since the guard already holds the lock,
        // try_lock() should fail (return false) for a non-recursive mutex.
        result.tryLockWithSafety = mutex.try_lock();

        // If it unexpectedly succeeded (e.g., recursive mutex), unlock it.
        if (result.tryLockWithSafety) {
            mutex.unlock();
        }
    } // 10. Exit guard scope

    // 11. Return conditional mutex result
    return result;
