  EXPECT_EQ(snapshot.orderedNames[0], "alpha");
  EXPECT_EQ(snapshot.orderedNames[1], "beta");
  EXPECT_EQ(snapshot.orderedNames[2], "gamma");
  EXPECT_TRUE(snapshot.allUnique);
}

}  // namespace test_reaction

